import chess
from functools import lru_cache

# Perfect minimax solver for few-piece endgames.
# Returns from side-to-move perspective: +1 win, 0 draw, -1 loss (mate by promotion->mate handled via depth)
# We solve "can White force a win" treating goal = White promotes and mates, or wins material then promotes.
# Simpler & rigorous: full game-theoretic value via retrograde over reachable positions with repetition=draw.

import sys
sys.setrecursionlimit(100000)

def value(board, depth, seen):
    # seen: frozenset of positions on current line (for repetition -> draw)
    if board.is_checkmate():
        return -1  # side to move is mated -> loss for stm
    if board.is_stalemate() or board.is_insufficient_material():
        return 0
    key = board._transposition_key()
    if key in seen:
        return 0  # repetition -> draw
    if depth == 0:
        return 0  # treat as draw if can't conclude (we'll use deep enough depth)
    seen2 = seen | {key}
    best = -2
    for mv in board.legal_moves:
        board.push(mv)
        # if a promotion to queen happened and it's now clearly winning, recurse normally
        v = -value(board, depth-1, seen2)
        board.pop()
        if v > best:
            best = v
        if best == 1:
            break
    return best

def evaluate(fen, depth=40):
    b = chess.Board(fen)
    return value(b, depth, frozenset())

# Candidate positions to test (White to move unless noted)
tests = {
 "A: WKd5 Pe5 / BKe7 Pe6 (facing e-pawns)": "4k3/8/4p3/3KP3/8/8/8/8 w - - 0 1",
 "B: WKe5 Pd5 / BKd7 (pawn on 5th, K beside)": "8/3k4/8/3PK3/8/8/8/8 w - - 0 1",
}
