    # counts
    c=defaultdict(int)
    for sq,pc in b.piece_map().items():
        c[pc.symbol()]+=1
    return c

def quick_terminal(b):
    """Return (is_terminal, value_for_white_abs) where value in {+1 white wins,0 draw,-1 black wins}
       using domain knowledge to prune promotions. None if not a quick terminal."""
    c=material_tuple(b)
    wq,bq=c['Q'],c['q']
    wp,bp=c['P'],c['p']
    wr,br=c['R'],c['r']
    # If one side has a queen (or rook) and the other has no pawn and no piece, it's a known win.
    white_pieces = wq+wr
    black_pieces = bq+br
    # White has Q/R, black has only king (no pawn, no piece) -> White wins (KQK/KRK are wins)
    if white_pieces>=1 and black_pieces==0 and bp==0:
        return True, +1
    if black_pieces>=1 and white_pieces==0 and wp==0:
        return True, -1
    # both promoted to queens, no pawns -> KQ vs KQ = draw (generally)
    if wq>=1 and bq>=1 and wp==0 and bp==0 and wr==0 and br==0:
        return True, 0
    return None

def keyf(b):
    return (b.board_fen(), b.turn, b.ep_square)

