import chess, sys, time
from collections import defaultdict, deque
sys.setrecursionlimit(1000000)

def material_counts(b):
    c=defaultdict(int)
    for pc in b.piece_map().values():
        c[pc.symbol()]+=1
    return c

def quick_terminal(b):
    """Domain pruning so promotions don't blow up the closure.
    Base material is K+P(s) vs K+P(s). Any NEW major piece (Q/R) decides instantly:
    side that just got a queen/rook while opponent has no major and no pawn -> that side wins."""
    c=material_counts(b)
    wq,bq=c['Q']+c['R'],c['q']+c['r']
    wp,bp=c['P'],c['p']
    if wq>=1 and bq==0 and bp==0:
        return +1
    if bq>=1 and wq==0 and wp==0:
        return -1
    if wq>=1 and bq>=1:
        return 0  # both queened, no pawns left -> practical draw for our purposes
    return None

def keyf(b):
    return (b.board_fen(), b.turn, b.ep_square)

def solve(root_fen, cap=4_000_000):
    states=set(); adj={}; terminal_stm={}
    stack=[root_fen]
    while stack:
        fen=stack.pop()
        b=chess.Board(fen)
        k=keyf(b)
        if k in states: continue
        states.add(k)
        if b.is_checkmate(): terminal_stm[k]=-1; adj[k]=[]; continue
        if b.is_stalemate() or b.is_insufficient_material(): terminal_stm[k]=0; adj[k]=[]; continue
        qt=quick_terminal(b)
        if qt is not None:
            terminal_stm[k]= qt if b.turn==chess.WHITE else -qt
            adj[k]=[]; continue
        ch=[]
        for mv in b.legal_moves:
            b.push(mv); ck=keyf(b); ch.append(ck)
            if ck not in states: stack.append(b.fen())
            b.pop()
        adj[k]=ch
        if len(states)>cap:
            raise RuntimeError("cap exceeded "+str(len(states)))
    # WDL retrograde labeling
    val=dict(terminal_stm)
    radj=defaultdict(list); degree={}
    for k,ch in adj.items():
        degree[k]=len(ch)
        for c in ch: radj[c].append(k)
    q=deque(terminal_stm.keys()); winc=defaultdict(int)
    while q:
        k=q.popleft(); v=val[k]
        for p in radj[k]:
            if p in val: continue
            if v==-1: val[p]=1; q.append(p)
            elif v==1:
                winc[p]+=1
                if winc[p]==degree[p]: val[p]=-1; q.append(p)
    for k in states: val.setdefault(k,0)
    return val, states, adj

def best_line(root_fen, val, adj, maxlen=40):
    b=chess.Board(root_fen); line=[]
    for _ in range(maxlen):
        k=keyf(b)
        if k not in adj or not adj[k]: break
        myval=val[k]; chosen=None
        for mv in b.legal_moves:
            b.push(mv); ck=keyf(b); cv=val.get(ck,0); b.pop()
            if -cv==myval: chosen=mv; break
        if chosen is None: chosen=list(b.legal_moves)[0]
        line.append(b.san(chosen)); b.push(chosen)
        if b.is_game_over(): break
        if quick_terminal(b) is not None: line.append("(decided)"); break
    return line

def run_one(name,fen):
    t=time.time()
    try:
        val,states,adj=solve(fen)
    except RuntimeError as e:
        print(name,"CAP",e); return None
    v=val[keyf(chess.Board(fen))]
    res={1:"WHITE WINS",0:"DRAW",-1:"WHITE LOSES"}[v]
    print(f"{name}: {res}  states={len(states)} ({time.time()-t:.1f}s)")
    print("   line:"," ".join(best_line(fen,val,adj)))
    sys.stdout.flush()
    return v,val,adj
